/**
 * @summary Get inventory differences summary report
 */
export const getGetInventoryDifferencesSummaryUrl = (
  params?: GetInventoryDifferencesSummaryParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/physical-counts/summary?${stringifiedParams}`
    : `/api/physical-counts/summary`;
};

